import{_ as e,a as i,b as t,c as o}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as l,o as n,c as r,a2 as d}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Trasferimento Magnet","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/Other/magnet-transfer.md","filePath":"it-IT/Other/magnet-transfer.md","lastUpdated":1781962217000}'),s={name:"it-IT/Other/magnet-transfer.md"};function p(c,a,m,u,h,g){return n(),r("div",null,[...a[0]||(a[0]=[d('<h1 id="trasferimento-magnet" tabindex="-1">Trasferimento Magnet <a class="header-anchor" href="#trasferimento-magnet" aria-label="Permalink to &quot;Trasferimento Magnet&quot;">​</a></h1><p>Il trasferimento Magnet scarica file da un magnet link e li carica automaticamente nel canale cloud che scegli.</p><p>È utile per episodi anime, video, archivi e file simili. Incolli un magnet link e ImgBed crea un&#39;attività di download in background. Al termine del download, il file viene caricato in ImgBed e il link finale compare nella lista upload.</p><p><img src="'+e+'" alt="Trasferimento Magnet" loading="lazy"></p><h2 id="dove-usarlo" tabindex="-1">Dove usarlo <a class="header-anchor" href="#dove-usarlo" aria-label="Permalink to &quot;Dove usarlo&quot;">​</a></h2><p>L&#39;ingresso del trasferimento Magnet si trova nell&#39;area upload della homepage.</p><p>Incolla il magnet link nella casella, scegli <code>Transfer</code>, poi carica.</p><p><img src="'+i+'" alt="Carica anime" loading="lazy"></p><h2 id="prima-del-primo-utilizzo" tabindex="-1">Prima del primo utilizzo <a class="header-anchor" href="#prima-del-primo-utilizzo" aria-label="Permalink to &quot;Prima del primo utilizzo&quot;">​</a></h2><p>Configura prima il trasferimento Magnet nel pannello admin.</p><p>Di solito servono:</p><ol><li>Un account GitHub per eseguire l&#39;attività di download.</li><li>Un canale di upload cloud, per esempio Google Drive o OneDrive.</li><li>La directory di destinazione.</li><li>Un timeout attività.</li></ol><p>Quando le impostazioni sono pronte, torna alla homepage e incolla un magnet link per avviare il trasferimento.</p><h2 id="caricare-un-magnet-link" tabindex="-1">Caricare un magnet link <a class="header-anchor" href="#caricare-un-magnet-link" aria-label="Permalink to &quot;Caricare un magnet link&quot;">​</a></h2><ol><li>Incolla il magnet link nella casella upload della homepage.</li><li>Assicurati che la modalità sia <code>Transfer</code>.</li><li>Clicca upload.</li><li>Attendi che ImgBed crei l&#39;attività magnet.</li><li>Dopo l&#39;avvio, usa il pannello flottante <code>Magnet Tasks</code> in basso a destra per seguire l&#39;avanzamento.</li></ol><p>Download e upload possono richiedere tempo. La velocità dipende dalla risorsa magnet, dall&#39;ambiente runtime GitHub e dal canale cloud selezionato.</p><p><img src="'+t+'" alt="Magnet in download" loading="lazy"></p><h2 id="dopo-il-completamento" tabindex="-1">Dopo il completamento <a class="header-anchor" href="#dopo-il-completamento" aria-label="Permalink to &quot;Dopo il completamento&quot;">​</a></h2><p>Quando l&#39;attività termina, la lista upload mostra nome file e link.</p><p>I video mostrano anteprima video, le immagini anteprima immagine, gli altri file una normale icona file.</p><p><img src="'+o+'" alt="Video scaricato" loading="lazy"></p><p>Puoi copiare:</p><table tabindex="0"><thead><tr><th>Tipo link</th><th>Uso</th></tr></thead><tbody><tr><td>Link originale</td><td>Accesso diretto al file</td></tr><tr><td>Markdown</td><td>Post o note Markdown</td></tr><tr><td>HTML</td><td>Codice pagina web</td></tr><tr><td>BBCode</td><td>Forum che supportano BBCode</td></tr></tbody></table><h2 id="pannello-attivita-magnet" tabindex="-1">Pannello attività Magnet <a class="header-anchor" href="#pannello-attivita-magnet" aria-label="Permalink to &quot;Pannello attività Magnet&quot;">​</a></h2><p>Il pannello in basso a destra mostra numero attività, nome attività, progresso e stato finale.</p><p>Stati comuni:</p><table tabindex="0"><thead><tr><th>Stato</th><th>Significato</th></tr></thead><tbody><tr><td>Waiting</td><td>L&#39;attività è stata creata ed è in attesa.</td></tr><tr><td>Downloading</td><td>La risorsa magnet è in download.</td></tr><tr><td>Uploading</td><td>Il file è stato scaricato e viene caricato sullo storage cloud.</td></tr><tr><td>Completed</td><td>Upload riuscito, il link può essere copiato.</td></tr><tr><td>Failed</td><td>L&#39;attività non è terminata correttamente. Controlla il messaggio e riprova.</td></tr></tbody></table><h2 id="consigli" tabindex="-1">Consigli <a class="header-anchor" href="#consigli" aria-label="Permalink to &quot;Consigli&quot;">​</a></h2><ul><li>Se un magnet contiene più file, ImgBed dà priorità al file principale completato per la visualizzazione.</li><li>I file grandi richiedono più tempo. Attendi la fine dell&#39;attività prima di aggiornare la pagina.</li><li>Se la risorsa magnet non ha peer disponibili, può essere molto lenta o fallire.</li><li>Se l&#39;account cloud ha quota esaurita, autorizzazione scaduta o directory errata, l&#39;attività può fallire.</li><li>L&#39;anteprima video può richiedere qualche secondo dopo l&#39;upload.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="non-parte-nulla-dopo-aver-incollato-il-magnet-link" tabindex="-1">Non parte nulla dopo aver incollato il magnet link <a class="header-anchor" href="#non-parte-nulla-dopo-aver-incollato-il-magnet-link" aria-label="Permalink to &quot;Non parte nulla dopo aver incollato il magnet link&quot;">​</a></h3><p>Controlla che il trasferimento Magnet sia abilitato nel pannello admin e che siano selezionati un account GitHub e un canale cloud utilizzabili.</p><h3 id="il-download-e-sempre-lento" tabindex="-1">Il download è sempre lento <a class="header-anchor" href="#il-download-e-sempre-lento" aria-label="Permalink to &quot;Il download è sempre lento&quot;">​</a></h3><p>La velocità Magnet dipende dalla risorsa. Se non ci sono peer disponibili, il download può essere lentissimo o impossibile.</p><h3 id="dopo-l-upload-non-appare-l-anteprima" tabindex="-1">Dopo l&#39;upload non appare l&#39;anteprima <a class="header-anchor" href="#dopo-l-upload-non-appare-l-anteprima" aria-label="Permalink to &quot;Dopo l&#39;upload non appare l&#39;anteprima&quot;">​</a></h3><p>Prima verifica che il link del file si apra. I video possono richiedere un po&#39; di tempo nel browser; in alternativa apri direttamente il link.</p><h3 id="cosa-controllo-se-un-attivita-fallisce" tabindex="-1">Cosa controllo se un&#39;attività fallisce? <a class="header-anchor" href="#cosa-controllo-se-un-attivita-fallisce" aria-label="Permalink to &quot;Cosa controllo se un&#39;attività fallisce?&quot;">​</a></h3><p>Controlla che il magnet link sia valido, che il canale cloud funzioni e che la directory di upload sia corretta. Poi invia di nuovo l&#39;attività.</p>',38)])])}const k=l(s,[["render",p]]);export{b as __pageData,k as default};
